// DJ OPUS - SECTION 5: THE RISE
// Building from nothing to everything
setcps(138/60/4)

let riseFilter = slider(600, 200, 12000, 10, "RISE Filter")
let tension = slider(0.2, 0, 1, 0.01, "TENSION")

// Diva still holding
let diva = note("<[a3,e4] [f3,c4] [d3,a3] [e3,b3]>".slow(2))
  .s("gm_voice_oohs")
  .gain(0.45)
  .room(0.9)
  .size(0.95)
  .cutoff(riseFilter)
  .vowel("<a e i o>".slow(4))

// Synth choir joining
let choir = note("<[a3,c4,e4] [f3,a3,c4] [d3,f3,a3] [e3,g3,b3]>".slow(2))
  .s("gm_synth_choir")
  .gain(tension.mul(0.4))
  .room(0.85)

// Snare roll building
let snare = s("sd").bank("RolandTR909")
  .gain(tension.mul(0.6))
  .struct("x x x x x x x x")
  .room(0.4)

// Kick ghost hits returning
let kickGhost = s("bd").bank("RolandTR909")
  .gain(tension.mul(0.5))
  .struct("x ~ ~ ~ x ~ ~ ~")

// Rising pad
let risePad = note("<a2 f2 d2 e2>".slow(2))
  .s("gm_pad_sweep")
  .gain(tension.mul(0.4))
  .cutoff(riseFilter)
  .room(0.9)
  .size(0.95)

// Noise riser
let noise = s("hh").bank("RolandTR909")
  .speed(0.1)
  .cutoff(riseFilter)
  .resonance(18)
  .gain(tension.mul(0.35))
  .room(0.95)
  .size(0.95)
  .struct("x x x x")

// Arp teasing the melody
let arp = note("a4 ~ e5 ~ c5 ~ a5 ~")
  .s("triangle")
  .cutoff(riseFilter)
  .decay(0.1)
  .sustain(0)
  .gain(tension.mul(0.25))
  .delay(0.5)
  .delaytime(3/16)
  .delayfeedback(0.5)
  .room(0.6)

stack(diva, choir, snare, kickGhost, risePad, noise, arp)
